// Parse the LLM decision robustly and expose clean fields for downstream provisioners.
const rawOut = $input.first().json.output;
const raw = (rawOut && typeof rawOut === 'object' && 'text' in rawOut) ? rawOut.text : rawOut;
const body = $('Workday Webhook Trigger').item.json.body;

const safeEmail = `${(body.first_name || '').toLowerCase().trim()}.${(body.last_name || '').toLowerCase().trim()}@helioshr.com`;

let decision;
try {
  decision = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  // LLM returned non-JSON -> fall back to safe defaults (governance: never block onboarding on a bad LLM response)
  decision = {
    email: safeEmail,
    systems: ['Okta', 'Google Workspace', 'Slack', 'Jira'],
    onboarding_message: `Welcome ${body.first_name}! Your accounts are being provisioned.`,
    risk_notes: 'LLM output was not valid JSON; applied safe default access set.'
  };
}

// Validate email domain (access governance: external domains are never provisioned).
const email = (typeof decision.email === 'string' && /@helioshr\.com$/.test(decision.email))
  ? decision.email.toLowerCase()
  : safeEmail;

const systems = Array.isArray(decision.systems) && decision.systems.length ? decision.systems : ['Okta', 'Google Workspace', 'Slack', 'Jira'];

return [{
  json: {
    email,
    username: email.split('@')[0],
    systems,
    onboarding_message: decision.onboarding_message || `Welcome ${body.first_name}!`,
    risk_notes: decision.risk_notes || 'none',
    first_name: body.first_name,
    last_name: body.last_name,
    department: body.department,
    title: body.title
  }
}];

